contracts/NationalIdentity.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

/**
 * NationalIdentity
 *
 * Prototype flow:
 *  - A trusted backend (Fayda attester) verifies the citizen with Fayda OTP + eKYC.
 *  - Backend signs an attestation. The citizen submits that attestation to register & auto-approve.
 *
 * This removes mock verification and removes the "manual admin approvals for millions".
 */
contract NationalIdentity is AccessControl, Pausable, ReentrancyGuard {
    using MessageHashUtils for bytes32;

    // Roles
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant EMPLOYER_ROLE = keccak256("EMPLOYER_ROLE");
    bytes32 public constant TAX_COLLECTOR_ROLE = keccak256("TAX_COLLECTOR_ROLE");

    // ECDSA signer that attests Fayda results + tax category.
    address public faydaAttester;

    enum TaxCategory {
        GOVERNMENT,
        CATEGORY_A,
        CATEGORY_B,
        MICRO
    }

    enum BusinessType {
        RETAIL,
        SERVICES,
        MANUFACTURING,
        AGRICULTURE,
        OTHER
    }

    enum Location {
        ADDIS_ABABA,
        OROMIA,
        AMHARA,
        TIGRAY,
        OTHER
    }

    struct Citizen {
        string fullName; // for admin display only in this prototype
        bytes32 faydaHash; // privacy-preserving hash of Fayda ID (UIN/VID)

        TaxCategory taxCategory;
        BusinessType businessType; // used for CATEGORY_B and MICRO
        Location area; // used for CATEGORY_B
        address linkedBankAccount; // used for CATEGORY_A (reference, not real bank account)

        uint8 age;
        bool isFaydaVerified;
        bool isOnSanctionsList;

        bool isAutoApproved;
        bool needsManualReview;
        uint256 registrationTime;
        uint256 lastFaydaVerification;
        uint256 approvalTimestamp;

        address registeredBy;
    }

    mapping(address => Citizen) private citizens;
    mapping(bytes32 => address) private faydaHashToAddress;
    address[] private registeredAddresses;
    mapping(bytes32 => bool) private usedAttestations;

    event CitizenRegistered(address indexed citizen, bytes32 indexed faydaHash, TaxCategory taxCategory);
    event CitizenAutoApproved(address indexed citizen, uint256 timestamp);
    event CitizenManualApproved(address indexed citizen, uint256 timestamp);
    event CitizenManualRejected(address indexed citizen, uint256 timestamp);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(EMPLOYER_ROLE, msg.sender);
        _grantRole(TAX_COLLECTOR_ROLE, msg.sender);
    }

    function setFaydaAttester(address signer) external onlyRole(ADMIN_ROLE) {
        faydaAttester = signer;
    }

    function pause() external onlyRole(ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(ADMIN_ROLE) {
        _unpause();
    }

    // --------- Registration / Auto-approval ----------

    function registerAndAutoApprove(
        bytes32 attestationId,
        string calldata _fullName,
        bytes32 _faydaHash,
        uint8 _age,
        bool _faydaVerified,
        bool _onSanctionsList,
        TaxCategory _taxCategory,
        BusinessType _businessType,
        Location _area,
        address _linkedBankAccount,
        bytes calldata signature
    ) external nonReentrant whenNotPaused {
        require(faydaAttester != address(0), "Fayda attester not configured");
        require(bytes(_fullName).length > 0, "Name required");
        require(citizens[msg.sender].registrationTime == 0, "Already registered");
        require(faydaHashToAddress[_faydaHash] == address(0), "Fayda ID already registered");
        require(!usedAttestations[attestationId], "Attestation already used");

        // Verify attestation signature (prevents lying about age/sanctions/category)
        bytes32 digest = keccak256(
            abi.encode(
                attestationId,
                msg.sender,
                _faydaHash,
                _age,
                _faydaVerified,
                _onSanctionsList,
                uint8(_taxCategory),
                uint8(_businessType),
                uint8(_area),
                _linkedBankAccount
            )
        );

        bytes32 messageHash = digest.toEthSignedMessageHash();
        address recovered = ECDSA.recover(messageHash, signature);
        require(recovered == faydaAttester, "Invalid attestation signature");

        usedAttestations[attestationId] = true;

        Citizen storage c = citizens[msg.sender];
        c.fullName = _fullName;
        c.faydaHash = _faydaHash;
        c.taxCategory = _taxCategory;
        c.businessType = _businessType;
        c.area = _area;
        c.linkedBankAccount = _linkedBankAccount;
        c.age = _age;
        c.isFaydaVerified = _faydaVerified;
        c.isOnSanctionsList = _onSanctionsList;
        c.registrationTime = block.timestamp;
        c.lastFaydaVerification = block.timestamp;
        c.registeredBy = msg.sender;

        // Auto-approval criteria
        bool eligible = _faydaVerified && (_age >= 18) && !_onSanctionsList && _isCategoryConfigured(_taxCategory, _businessType, _area, _linkedBankAccount);
        c.isAutoApproved = eligible;
        c.needsManualReview = !eligible;
        if (eligible) {
            c.approvalTimestamp = block.timestamp;
            emit CitizenAutoApproved(msg.sender, c.approvalTimestamp);
        }

        faydaHashToAddress[_faydaHash] = msg.sender;
        registeredAddresses.push(msg.sender);
        emit CitizenRegistered(msg.sender, _faydaHash, _taxCategory);
    }

    function _isCategoryConfigured(
        TaxCategory _taxCategory,
        BusinessType _businessType,
        Location _area,
        address _linkedBankAccount
    ) internal pure returns (bool) {
        // Minimal validation for prototype:
        // - CATEGORY_B requires a business type + location
        // - MICRO requires a business type
        // - CATEGORY_A requires a bank account reference
        if (_taxCategory == TaxCategory.CATEGORY_B) {
            return (_businessType != BusinessType.OTHER) && (_area != Location.OTHER);
        }
        if (_taxCategory == TaxCategory.MICRO) {
            return (_businessType != BusinessType.OTHER);
        }
        if (_taxCategory == TaxCategory.CATEGORY_A) {
            return (_linkedBankAccount != address(0));
        }
        // GOVERNMENT does not require extra fields in this prototype
        return true;
    }

    // --------- Manual review (edge cases) ----------

    function manualApprove(address citizen) public onlyRole(ADMIN_ROLE) {
        Citizen storage c = citizens[citizen];
        require(c.registrationTime != 0, "Citizen not found");
        require(!c.isAutoApproved, "Already auto-approved");
        c.isAutoApproved = true;
        c.needsManualReview = false;
        c.approvalTimestamp = block.timestamp;
        emit CitizenManualApproved(citizen, c.approvalTimestamp);
    }

    function manualReject(address citizen) public onlyRole(ADMIN_ROLE) {
        Citizen storage c = citizens[citizen];
        require(c.registrationTime != 0, "Citizen not found");
        require(!c.isAutoApproved, "Already approved");
        c.isAutoApproved = false;
        c.needsManualReview = false;
        emit CitizenManualRejected(citizen, block.timestamp);
    }

    function batchManualApprove(address[] calldata citizenWallets) external onlyRole(ADMIN_ROLE) {
        for (uint256 i = 0; i < citizenWallets.length; i++) {
            manualApprove(citizenWallets[i]);
        }
    }

    // --------- Getters for frontend ----------

    function isAutoApprovedCitizen(address citizen) external view returns (bool) {
        return citizens[citizen].isAutoApproved;
    }

    function taxCategoryOf(address citizen) external view returns (TaxCategory) {
        return citizens[citizen].taxCategory;
    }

    function businessTypeOf(address citizen) external view returns (BusinessType) {
        return citizens[citizen].businessType;
    }

    function locationOf(address citizen) external view returns (Location) {
        return citizens[citizen].area;
    }

    function linkedBankAccountOf(address citizen) external view returns (address) {
        return citizens[citizen].linkedBankAccount;
    }

    function getCitizenPublic(address citizen) external view returns (
        TaxCategory taxCategory,
        bool isFaydaVerified,
        bool isAutoApproved,
        bool needsManualReview,
        uint256 approvalTimestamp,
        uint256 registrationTime
    ) {
        Citizen memory c = citizens[citizen];
        require(c.registrationTime != 0, "Citizen not found");
        return (
            c.taxCategory,
            c.isFaydaVerified,
            c.isAutoApproved,
            c.needsManualReview,
            c.approvalTimestamp,
            c.registrationTime
        );
    }

    function getCitizenAdmin(address citizen) external view onlyRole(ADMIN_ROLE) returns (
        string memory fullName,
        bytes32 faydaHash,
        TaxCategory taxCategory,
        uint8 age,
        bool isFaydaVerified,
        bool isOnSanctionsList,
        bool isAutoApproved,
        bool needsManualReview,
        uint256 approvalTimestamp,
        uint256 registrationTime
    ) {
        Citizen memory c = citizens[citizen];
        require(c.registrationTime != 0, "Citizen not found");
        return (
            c.fullName,
            c.faydaHash,
            c.taxCategory,
            c.age,
            c.isFaydaVerified,
            c.isOnSanctionsList,
            c.isAutoApproved,
            c.needsManualReview,
            c.approvalTimestamp,
            c.registrationTime
        );
    }

    function resolveWalletFromFaydaHash(bytes32 faydaHash) external view onlyRole(TAX_COLLECTOR_ROLE) returns (address) {
        return faydaHashToAddress[faydaHash];
    }

    function resolveWalletFromFaydaNumber(uint256 faydaNumber) external view onlyRole(TAX_COLLECTOR_ROLE) returns (address) {
        bytes32 h = keccak256(abi.encodePacked(faydaNumber));
        return faydaHashToAddress[h];
    }

    function getAllCitizens() external view onlyRole(ADMIN_ROLE) returns (address[] memory) {
        return registeredAddresses;
    }

    function getTotalCitizens() external view returns (uint256) {
        return registeredAddresses.length;
    }
}

contracts/StaticTaxHandler.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./NationalIdentity.sol";

/**
 * StaticTaxHandler
 *
 * Production prototype changes:
 *  - No income self-reporting (citizens/employers never submit income figures)
 *  - Category-based tax calculation (A uses bank deposits oracle; B/Micro use fixed tables)
 */
contract StaticTaxHandler is Ownable, AccessControl, ReentrancyGuard {
    NationalIdentity public identityContract;

    bytes32 public constant BANK_ORACLE_ROLE = keccak256("BANK_ORACLE_ROLE");
    bytes32 public constant GOVERNMENT_ORACLE_ROLE = keccak256("GOVERNMENT_ORACLE_ROLE");
    bytes32 public constant TAX_COLLECTOR_ROLE = keccak256("TAX_COLLECTOR_ROLE");

    // For demo we treat "ETB amounts" as 1 ETB = 1e15 wei (so amounts are payable but not huge).
    uint256 public constant ETB_TO_WEI = 1e15;

    // Category A: deposits * 30%
    uint256 public constant CATEGORY_A_RATE_BPS = 3000; // 30.00% (bps / 10000)

    struct TaxRecord {
        uint256 totalTaxPaid;
        uint256 lastPaymentTimestamp;
        bool exists;
    }

    mapping(address => TaxRecord) private taxRecords;
    uint256 public totalTaxCollected;

    // Oracle-provided values
    mapping(address => uint256) public categoryADepositsAnnualWei; // annual deposits in wei(ETB)
    mapping(address => uint256) public governmentTaxAnnualWei; // annual due for GOVERNMENT category

    event TaxPaid(address indexed citizen, uint256 amountWei, NationalIdentity.TaxCategory category, uint256 timestamp);
    event EmployerWithholding(address indexed employer, address indexed employee, uint256 amountWei, uint256 timestamp);
    event DepositsUpdated(address indexed business, uint256 annualDepositsWei, uint256 timestamp);
    event GovernmentWithholdingUpdated(address indexed employee, uint256 annualTaxWei, uint256 timestamp);

    constructor(address _identityContract) Ownable(msg.sender) {
        identityContract = NationalIdentity(_identityContract);

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(BANK_ORACLE_ROLE, msg.sender);
        _grantRole(GOVERNMENT_ORACLE_ROLE, msg.sender);
        _grantRole(TAX_COLLECTOR_ROLE, msg.sender);
    }

    // ----------------- Category Tax Calculations -----------------

    function calculateTaxForCategoryA(address business) public view returns (uint256) {
        uint256 deposits = categoryADepositsAnnualWei[business];
        return (deposits * CATEGORY_A_RATE_BPS) / 10000;
    }

    function calculateTaxForCategoryB(
        NationalIdentity.BusinessType businessType,
        NationalIdentity.Location area
    ) public pure returns (uint256) {
        // Prototype fixed table:
        // - Annual presumptive sales (ETB) are fixed per (businessType, location)
        // - Tax rate varies between 2% and 9%
        uint256 salesEtb = _categoryBSalesEtbAnnual(businessType, area);
        uint256 rateBps = _categoryBRateBps(businessType, area);
        uint256 taxEtb = (salesEtb * rateBps) / 10000;
        return taxEtb * ETB_TO_WEI;
    }

    function calculateTaxForMicro(
        NationalIdentity.BusinessType businessType
    ) public pure returns (uint256) {
        // Flat monthly payment (ETB), dependent on business type.
        uint256 monthlyEtb = _microMonthlyEtb(businessType);
        return monthlyEtb * ETB_TO_WEI;
    }

    function calculateTaxForGovernment(address employee) public view returns (uint256) {
        return governmentTaxAnnualWei[employee];
    }

    function taxDueNow(address citizen) public view returns (uint256) {
        NationalIdentity.TaxCategory cat = identityContract.taxCategoryOf(citizen);
        if (cat == NationalIdentity.TaxCategory.GOVERNMENT) {
            return calculateTaxForGovernment(citizen);
        }
        if (cat == NationalIdentity.TaxCategory.CATEGORY_A) {
            return calculateTaxForCategoryA(citizen);
        }
        if (cat == NationalIdentity.TaxCategory.CATEGORY_B) {
            return calculateTaxForCategoryB(identityContract.businessTypeOf(citizen), identityContract.locationOf(citizen));
        }
        // MICRO
        return calculateTaxForMicro(identityContract.businessTypeOf(citizen));
    }

    // ----------------- Payments -----------------

    function payTax() external payable nonReentrant {
        require(identityContract.isAutoApprovedCitizen(msg.sender), "Citizen not auto-approved");

        NationalIdentity.TaxCategory cat = identityContract.taxCategoryOf(msg.sender);
        require(cat == NationalIdentity.TaxCategory.CATEGORY_B || cat == NationalIdentity.TaxCategory.MICRO, "Citizen payments disabled for this category");

        uint256 dueWei = taxDueNow(msg.sender);
        require(dueWei > 0, "No tax due");
        require(msg.value >= dueWei, "Insufficient payment");

        _recordTax(msg.sender, dueWei, cat, msg.sender);
    }

    function employerWithhold(address employee) external payable nonReentrant {
        require(identityContract.hasRole(identityContract.EMPLOYER_ROLE(), msg.sender), "Not an authorized employer");
        require(identityContract.isAutoApprovedCitizen(employee), "Employee not auto-approved");

        uint256 dueWei = taxDueNow(employee);
        require(dueWei > 0, "No tax due");
        require(msg.value >= dueWei, "Insufficient withholding amount");

        NationalIdentity.TaxCategory cat = identityContract.taxCategoryOf(employee);
        _recordTax(employee, dueWei, cat, msg.sender);

        emit EmployerWithholding(msg.sender, employee, dueWei, block.timestamp);
    }

    function _recordTax(address citizen, uint256 amountWei, NationalIdentity.TaxCategory category, address payer) internal {
        (payer); // payer reserved for future audit data

        TaxRecord storage r = taxRecords[citizen];
        r.totalTaxPaid += amountWei;
        r.lastPaymentTimestamp = block.timestamp;
        r.exists = true;

        totalTaxCollected += amountWei;

        emit TaxPaid(citizen, amountWei, category, block.timestamp);
    }

    // ----------------- Oracle Updates -----------------

    function updateDepositsFromBank(address business, uint256 annualDepositsWei) external onlyRole(BANK_ORACLE_ROLE) {
        require(business != address(0), "Invalid business");
        categoryADepositsAnnualWei[business] = annualDepositsWei;
        emit DepositsUpdated(business, annualDepositsWei, block.timestamp);
    }

    function updateGovernmentWithholding(address employee, uint256 annualTaxWei) external onlyRole(GOVERNMENT_ORACLE_ROLE) {
        require(employee != address(0), "Invalid employee");
        governmentTaxAnnualWei[employee] = annualTaxWei;
        emit GovernmentWithholdingUpdated(employee, annualTaxWei, block.timestamp);
    }

    // ----------------- Read Access Control -----------------

    function getTaxRecord(address citizen) external view returns (
        bool exists,
        uint256 totalTaxPaid,
        uint256 lastPaymentTimestamp
    ) {
        require(
            citizen == msg.sender || hasRole(TAX_COLLECTOR_ROLE, msg.sender),
            "Not authorized to view tax record"
        );
        TaxRecord memory r = taxRecords[citizen];
        return (r.exists, r.totalTaxPaid, r.lastPaymentTimestamp);
    }

    // ----------------- Withdraw -----------------

    function withdrawRevenue(uint256 amountWei) external onlyOwner {
        require(amountWei <= address(this).balance, "Insufficient balance");
        payable(owner()).transfer(amountWei);
    }

    function _categoryBSalesEtbAnnual(
        NationalIdentity.BusinessType businessType,
        NationalIdentity.Location area
    ) internal pure returns (uint256) {
        // Fixed sales assumptions (ETB/year) for demo.
        // Keeping numbers small-ish for testnet UX.
        uint256 base;
        if (businessType == NationalIdentity.BusinessType.RETAIL) base = 2_000_000;
        else if (businessType == NationalIdentity.BusinessType.SERVICES) base = 3_500_000;
        else if (businessType == NationalIdentity.BusinessType.MANUFACTURING) base = 4_500_000;
        else if (businessType == NationalIdentity.BusinessType.AGRICULTURE) base = 1_500_000;
        else base = 2_500_000;

        // Fixed multipliers using integer math (prototype only).
        // OROMIA: 1.5x, AMHARA: 1.2x, TIGRAY: 1.1x.
        if (area == NationalIdentity.Location.ADDIS_ABABA) return base * 2;
        if (area == NationalIdentity.Location.OROMIA) return (base * 15) / 10;
        if (area == NationalIdentity.Location.AMHARA) return (base * 12) / 10;
        if (area == NationalIdentity.Location.TIGRAY) return (base * 11) / 10;
        return base;
    }

    function _categoryBRateBps(
        NationalIdentity.BusinessType businessType,
        NationalIdentity.Location area
    ) internal pure returns (uint256) {
        // Rate between 2% and 9% (bps / 10000).
        uint256 rateBpsBase;
        if (businessType == NationalIdentity.BusinessType.RETAIL) rateBpsBase = 200; // 2%
        else if (businessType == NationalIdentity.BusinessType.SERVICES) rateBpsBase = 500; // 5%
        else if (businessType == NationalIdentity.BusinessType.MANUFACTURING) rateBpsBase = 650; // 6.5%
        else if (businessType == NationalIdentity.BusinessType.AGRICULTURE) rateBpsBase = 350; // 3.5%
        else rateBpsBase = 450; // 4.5%

        // Location adjustment (kept bounded to 2%-9% range)
        uint256 adj;
        if (area == NationalIdentity.Location.ADDIS_ABABA) adj = 250; // +2.5%
        else if (area == NationalIdentity.Location.OROMIA) adj = 150; // +1.5%
        else if (area == NationalIdentity.Location.AMHARA) adj = 100; // +1%
        else if (area == NationalIdentity.Location.TIGRAY) adj = 50; // +0.5%
        else adj = 0;

        uint256 rate = rateBpsBase + adj;
        if (rate < 200) return 200;
        if (rate > 900) return 900;
        return rate;
    }

    function _microMonthlyEtb(NationalIdentity.BusinessType businessType) internal pure returns (uint256) {
        if (businessType == NationalIdentity.BusinessType.RETAIL) return 220;
        if (businessType == NationalIdentity.BusinessType.SERVICES) return 280;
        if (businessType == NationalIdentity.BusinessType.MANUFACTURING) return 420;
        if (businessType == NationalIdentity.BusinessType.AGRICULTURE) return 240;
        return 320;
    }

    receive() external payable {}
}

